    assign Cout = obf_G[3] | (P[3] & obf_G[2]) | (P[3] & P[2] & obf_G[1]) | (P[3] & P[2] & P[1] & obf_G[0]) |(P[3] & P[2] & P[1] & P[0] & C[0]);
